// Language: JavaScript (React)
import React, { useState } from 'react';
import axios from 'axios';

const Booking = () => {
    const [bookingData, setBookingData] = useState({
        pickupLocation: '',
        dropLocation: '',
        cabType: 'Mini'
    });

    const { pickupLocation, dropLocation, cabType } = bookingData;

    const onChange = e => setBookingData({ ...bookingData, [e.target.name]: e.target.value });

    const onBook = async e => {
        e.preventDefault();
        try {
            // Placeholder fare for now
            const fare = cabType === 'SUV' ? 50 : 25; 
            const response = await axios.post('http://localhost:5000/api/ride/book', {
                ...bookingData,
                fare,
                passengerId: "REPLACE_WITH_LOGGED_IN_USER_ID" // We will automate this later
            });
            alert(response.data.message);
        } catch (err) {
            alert("Booking failed. Please check backend.");
        }
    };

    return (
        <div className="container mt-4">
            <div className="row">
                {/* Booking Form Side */}
                <div className="col-md-5 card p-4 shadow">
                    <h3>Book Your Ucab</h3>
                    <form onSubmit={onBook}>
                        <div className="mb-3">
                            <label>Pickup Location</label>
                            <input type="text" name="pickupLocation" className="form-control" value={pickupLocation} onChange={onChange} required />
                        </div>
                        <div className="mb-3">
                            <label>Drop Location</label>
                            <input type="text" name="dropLocation" className="form-control" value={dropLocation} onChange={onChange} required />
                        </div>
                        <div className="mb-3">
                            <label>Select Cab</label>
                            <select name="cabType" className="form-select" value={cabType} onChange={onChange}>
                                <option value="Mini">Ucab Mini ($25)</option>
                                <option value="Sedan">Ucab Sedan ($35)</option>
                                <option value="SUV">Ucab SUV ($50)</option>
                            </select>
                        </div>
                        <button type="submit" className="btn btn-primary w-100">Confirm Booking</button>
                    </form>
                </div>

                {/* Map Placeholder Side */}
                <div className="col-md-7">
                    <div className="bg-light border text-center p-5 shadow" style={{ height: '400px' }}>
                        <p className="mt-5 text-muted">Map will be integrated here (Leaflet/Google Maps)</p>
                        <div className="btn btn-outline-secondary btn-sm mt-3">Live GPS Tracking</div>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default Booking;
